mapper.select:
SELECT T.JOB_NM ,T.JOB_DATE ,T.JOB_END_DATE ,T.JOB_RLT ,T.JOB_RLT_MSG FROM (SELECT GETCODENAME(#{ses.gateCd}, 'M177', BL.JOB_ID, #{ses.langCd}) as JOB_NM
,TO_CHAR(BL.JOB_DATE, 'YYYY-MM-DD HH24:MI') AS JOB_DATE ,TO_CHAR(BL.JOB_END_DATE, 'YYYY-MM-DD HH24:MI') AS JOB_END_DATE
,CONVERT(CHAR(19), BL.JOB_DATE , 120) as JOB_DATE ,CONVERT(CHAR(19), BL.JOB_END_DATE , 120) as JOB_END_DATE
,BL.JOB_RLT ,(CASE BL.JOB_RLT WHEN 'E' THEN BL.JOB_RLT_MSG ELSE NULL END) as JOB_RLT_MSG FROM STOCBLOG BL WHERE BL.JOB_TYPE = 'Batch'
AND BL.JOB_DATE >= (#{JOB_DATE_FROM}) AND BL.JOB_DATE <= (#{JOB_DATE_TO})
AND BL.JOB_ID = #{JOB_NM}
AND BL.JOB_RLT = #{JOB_RLT}
) T WHERE 1 = 1 ORDER BY T.JOB_DATE DESC

mapper.insert:
INSERT INTO STOCBLOG
(
	 JOB_SQ
	,JOB_DATE
	,JOB_TYPE
	,JOB_ID
	,JOB_KEY
	,JOB_RLT
	,JOB_RLT_CD
	,JOB_RLT_MSG
	,JOB_END_DATE
)
VALUES
(
	 SEQ_STOCBLOG.NEXTVAL
	,(#{JOB_DATE}, 'YYYY-MM-DD HH24:MI')
	,#{JOB_TYPE}
	,#{JOB_ID}
	,#{JOB_KEY}
	,#{JOB_RLT}
	,#{JOB_RLT_CD}
	,#{JOB_RLT_MSG}
	,(#{JOB_END_DATE}, 'YYYY-MM-DD HH24:MI')
)
